+impl ConnectorProcessRunner {
+    async fn spawn(command: &str, args: &[&str], env: &[(&str, &str)]) -> std::io::Result<Self> {
+        let mut cmd = AsyncCommand::new(command);
+        cmd.args(args)
+            .stdin(AsyncStdio::piped())
+            .stdout(AsyncStdio::piped())
+            .stderr(AsyncStdio::piped())
+            .kill_on_drop(true);
+
